ye nimitte ailana tomara alaya',NULL,NULL),('cb.antya.6.75','cb','cb.antya.6','ЧБ Антья 6.75',75,NULL,'amara mayera chaya putra papi kamse marileka, sei pape seha maila sese',NULL,NULL),('cb.antya.6.76','cb','cb.antya.6','ЧБ Антья 6.76',76,NULL,'niravadhi sei putra-soka sanariya kandena devaki-mata duhkhita haiya',NULL,NULL),('cb.antya.6.77','cb','cb.antya.6','ЧБ Антья 6.77',77,NULL,'tomara nikate ache sei chaya jana taha niba jananira santosa-karana',NULL,NULL),('cb.antya.6.78','cb','cb.antya.6','ЧБ Антья 6.78',78,NULL,'se saba brahmara pautra siddha deva-gana ta''-sabara eta duhkha suna ye-karana',NULL,NULL),('cb.antya.6.79','cb','cb.antya.6','ЧБ Антья 6.79',79,NULL,'prajapati marici-ye brahmara nandana
